import{_ as o,o as r,c as a,a4 as t}from"./chunks/framework.BlZvSPPP.js";const p=JSON.parse('{"title":"Interface: Theme · core","description":"","frontmatter":{"title":"Interface: Theme · core"},"headers":[],"relativePath":"api/core/interfaces/Theme.md","filePath":"api/core/interfaces/Theme.md"}'),l={name:"api/core/interfaces/Theme.md"};function c(d,e,n,i,h,s){return r(),a("div",null,[...e[0]||(e[0]=[t('<p><a href="./../">@jsvision/core</a> / Theme</p><h1 id="interface-theme" tabindex="-1">Interface: Theme <a class="header-anchor" href="#interface-theme" aria-label="Permalink to &quot;Interface: Theme&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L30" target="_blank" rel="noreferrer">color/theme.ts:30</a></p><p>Named semantic UI roles mapped to colors. See <a href="./../variables/defaultTheme.html">defaultTheme</a>.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="button" tabindex="-1">button <a class="header-anchor" href="#button" aria-label="Permalink to &quot;button&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>button</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L57" target="_blank" rel="noreferrer">color/theme.ts:57</a></p><p>A normal command button face.</p><hr><h3 id="buttondefault" tabindex="-1">buttonDefault <a class="header-anchor" href="#buttondefault" aria-label="Permalink to &quot;buttonDefault&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>buttonDefault</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L70" target="_blank" rel="noreferrer">color/theme.ts:70</a></p><p>The default button&#39;s face when unfocused: brightCyan on green.</p><hr><h3 id="buttondisabled" tabindex="-1">buttonDisabled <a class="header-anchor" href="#buttondisabled" aria-label="Permalink to &quot;buttonDisabled&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>buttonDisabled</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L72" target="_blank" rel="noreferrer">color/theme.ts:72</a></p><p>A disabled button&#39;s face: darkGray on lightGray.</p><hr><h3 id="buttonfocused" tabindex="-1">buttonFocused <a class="header-anchor" href="#buttonfocused" aria-label="Permalink to &quot;buttonFocused&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>buttonFocused</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L59" target="_blank" rel="noreferrer">color/theme.ts:59</a></p><p>A focused command button face.</p><hr><h3 id="buttonshadow" tabindex="-1">buttonShadow <a class="header-anchor" href="#buttonshadow" aria-label="Permalink to &quot;buttonShadow&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>buttonShadow</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L80" target="_blank" rel="noreferrer">color/theme.ts:80</a></p><p>The button&#39;s drop-shadow blocks (<code>▄</code>/<code>█</code>/<code>▀</code>): black on lightGray. Painting black block glyphs over the dialog&#39;s own gray field produces the shadow. This is NOT the window drop-shadow (<a href="#shadow">shadow</a>, darkGray on black).</p><hr><h3 id="buttonshortcut" tabindex="-1">buttonShortcut <a class="header-anchor" href="#buttonshortcut" aria-label="Permalink to &quot;buttonShortcut&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>buttonShortcut</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L74" target="_blank" rel="noreferrer">color/theme.ts:74</a></p><p>A button&#39;s <code>~hotkey~</code> accent character: yellow on green.</p><hr><h3 id="calendarcursor" tabindex="-1">calendarCursor <a class="header-anchor" href="#calendarcursor" aria-label="Permalink to &quot;calendarCursor&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>calendarCursor</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L204" target="_blank" rel="noreferrer">color/theme.ts:204</a></p><p>A calendar&#39;s focus cursor — the navigable focus cell, drawn <strong>only while the calendar has focus</strong>, at highest precedence: black on white (a filled reverse block) so the focused day reads as a solid highlight against the cyan grid.</p><hr><h3 id="calendardisabled" tabindex="-1">calendarDisabled <a class="header-anchor" href="#calendardisabled" aria-label="Permalink to &quot;calendarDisabled&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>calendarDisabled</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L206" target="_blank" rel="noreferrer">color/theme.ts:206</a></p><p>A calendar&#39;s disabled day — dimmed but still navigable: darkGray on cyan.</p><hr><h3 id="calendarnormal" tabindex="-1">calendarNormal <a class="header-anchor" href="#calendarnormal" aria-label="Permalink to &quot;calendarNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>calendarNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L190" target="_blank" rel="noreferrer">color/theme.ts:190</a></p><p>A calendar&#39;s in-month day cell (normal): yellow on cyan.</p><hr><h3 id="calendarselected" tabindex="-1">calendarSelected <a class="header-anchor" href="#calendarselected" aria-label="Permalink to &quot;calendarSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>calendarSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L198" target="_blank" rel="noreferrer">color/theme.ts:198</a></p><p>A calendar&#39;s selected day — the committed value cell: white on blue, a distinct blue cell against the cyan grid. Takes precedence over <a href="#calendartoday">calendarToday</a> when they coincide.</p><hr><h3 id="calendartoday" tabindex="-1">calendarToday <a class="header-anchor" href="#calendartoday" aria-label="Permalink to &quot;calendarToday&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>calendarToday</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L192" target="_blank" rel="noreferrer">color/theme.ts:192</a></p><p>A calendar&#39;s &quot;today&quot; cell — the highlighted current date: blue on green.</p><hr><h3 id="calendarweeknumber" tabindex="-1">calendarWeekNumber <a class="header-anchor" href="#calendarweeknumber" aria-label="Permalink to &quot;calendarWeekNumber&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>calendarWeekNumber</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L208" target="_blank" rel="noreferrer">color/theme.ts:208</a></p><p>A calendar&#39;s ISO week-number column (the opt-in leading <code>NN</code> column): black on cyan.</p><hr><h3 id="clusterdisabled" tabindex="-1">clusterDisabled <a class="header-anchor" href="#clusterdisabled" aria-label="Permalink to &quot;clusterDisabled&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>clusterDisabled</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L88" target="_blank" rel="noreferrer">color/theme.ts:88</a></p><p>A disabled cluster item: darkGray on cyan.</p><hr><h3 id="clusternormal" tabindex="-1">clusterNormal <a class="header-anchor" href="#clusternormal" aria-label="Permalink to &quot;clusterNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>clusterNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L82" target="_blank" rel="noreferrer">color/theme.ts:82</a></p><p>A check/radio cluster item, normal: black on cyan.</p><hr><h3 id="clusterselected" tabindex="-1">clusterSelected <a class="header-anchor" href="#clusterselected" aria-label="Permalink to &quot;clusterSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>clusterSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L84" target="_blank" rel="noreferrer">color/theme.ts:84</a></p><p>A check/radio cluster item, focused: white on cyan.</p><hr><h3 id="clustershortcut" tabindex="-1">clusterShortcut <a class="header-anchor" href="#clustershortcut" aria-label="Permalink to &quot;clusterShortcut&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>clusterShortcut</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L86" target="_blank" rel="noreferrer">color/theme.ts:86</a></p><p>A cluster item&#39;s <code>~hotkey~</code> accent: yellow on cyan.</p><hr><h3 id="colormarker" tabindex="-1">colorMarker <a class="header-anchor" href="#colormarker" aria-label="Permalink to &quot;colorMarker&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>colorMarker</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L214" target="_blank" rel="noreferrer">color/theme.ts:214</a></p><p>The forced-contrast <code>◘</code> selection marker drawn on a near-black color-swatch cell: black on lightGray, so the marker stays visible against the dark cell. A normal (non-dark) cell&#39;s marker uses the cell&#39;s own color instead.</p><hr><h3 id="dangertext" tabindex="-1">dangerText <a class="header-anchor" href="#dangertext" aria-label="Permalink to &quot;dangerText&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>dangerText</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L295" target="_blank" rel="noreferrer">color/theme.ts:295</a></p><p>Danger/error body text — a validation error or alert line: danger-red on the static-text field.</p><hr><h3 id="desktop" tabindex="-1">desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to &quot;desktop&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>desktop</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a> &amp; <code>object</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L32" target="_blank" rel="noreferrer">color/theme.ts:32</a></p><p>The desktop fill: a role plus the repeating pattern glyph tiled across it.</p><h4 id="type-declaration" tabindex="-1">Type Declaration <a class="header-anchor" href="#type-declaration" aria-label="Permalink to &quot;Type Declaration&quot;">​</a></h4><h5 id="pattern" tabindex="-1">pattern <a class="header-anchor" href="#pattern" aria-label="Permalink to &quot;pattern&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>pattern</strong>: <code>string</code></p></blockquote><hr><h3 id="dialog" tabindex="-1">dialog <a class="header-anchor" href="#dialog" aria-label="Permalink to &quot;dialog&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>dialog</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a> &amp; <code>object</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L55" target="_blank" rel="noreferrer">color/theme.ts:55</a></p><p>The gray dialog chrome. <code>border</code>/<code>title</code> color the frame lines and title; <code>icon</code> is the accent for the close-box <code>[×]</code> glyph. The gray dialog palette is deliberately distinct from the blue <a href="#window">window</a>.</p><h4 id="type-declaration-1" tabindex="-1">Type Declaration <a class="header-anchor" href="#type-declaration-1" aria-label="Permalink to &quot;Type Declaration&quot;">​</a></h4><h5 id="border" tabindex="-1">border <a class="header-anchor" href="#border" aria-label="Permalink to &quot;border&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>border</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><h5 id="icon" tabindex="-1">icon <a class="header-anchor" href="#icon" aria-label="Permalink to &quot;icon&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>icon</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><h5 id="title" tabindex="-1">title <a class="header-anchor" href="#title" aria-label="Permalink to &quot;title&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>title</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><hr><h3 id="editornormal" tabindex="-1">editorNormal <a class="header-anchor" href="#editornormal" aria-label="Permalink to &quot;editorNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>editorNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L252" target="_blank" rel="noreferrer">color/theme.ts:252</a></p><p>Editor text — an editor/memo body&#39;s normal cell: yellow on blue.</p><hr><h3 id="editorselected" tabindex="-1">editorSelected <a class="header-anchor" href="#editorselected" aria-label="Permalink to &quot;editorSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>editorSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L254" target="_blank" rel="noreferrer">color/theme.ts:254</a></p><p>Editor selected text — the reverse-video selection band: blue on lightGray.</p><hr><h3 id="fileinfo" tabindex="-1">fileInfo <a class="header-anchor" href="#fileinfo" aria-label="Permalink to &quot;fileInfo&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>fileInfo</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L249" target="_blank" rel="noreferrer">color/theme.ts:249</a></p><p>A file dialog&#39;s info pane — the strip below the dialog that reads out the expanded path and the focused entry&#39;s name/size/date/time: cyan on blue.</p><hr><h3 id="gridcursor" tabindex="-1">gridCursor <a class="header-anchor" href="#gridcursor" aria-label="Permalink to &quot;gridCursor&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>gridCursor</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L221" target="_blank" rel="noreferrer">color/theme.ts:221</a></p><p>The focused <strong>cell</strong> highlight in an editable data grid — a filled black-on-white reverse block drawn over the focused row so the cursor cell reads distinctly inside the row highlight. Painted only while the grid body has focus.</p><hr><h3 id="griddirty" tabindex="-1">gridDirty <a class="header-anchor" href="#griddirty" aria-label="Permalink to &quot;gridDirty&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>gridDirty</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L227" target="_blank" rel="noreferrer">color/theme.ts:227</a></p><p>The pending-commit marker colour in an editable data grid: the <code>•</code> drawn on a cell whose edit has not yet been confirmed. Its foreground is composited over the cell&#39;s own background at draw time, so the stored background is nominal.</p><hr><h3 id="gridinvalid" tabindex="-1">gridInvalid <a class="header-anchor" href="#gridinvalid" aria-label="Permalink to &quot;gridInvalid&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>gridInvalid</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L244" target="_blank" rel="noreferrer">color/theme.ts:244</a></p><p>A cell whose edit failed validation in an editable data grid — a solid band (white on a deep red), distinct from both the <a href="#griddirty">gridDirty</a> pending-commit marker (a <code>•</code>, not a band) and the <a href="#gridcursor">gridCursor</a> focus. Painted over the whole invalid cell so a rejected value reads as a hard error; it wins over the dirty marker but yields to the focused-cell cursor.</p><hr><h3 id="gridselectedrow" tabindex="-1">gridSelectedRow <a class="header-anchor" href="#gridselectedrow" aria-label="Permalink to &quot;gridSelectedRow&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>gridSelectedRow</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L236" target="_blank" rel="noreferrer">color/theme.ts:236</a></p><p>A selected row in an editable data grid — the multi-row selection highlight, a solid band distinct from both the focused-cell <a href="#gridcursor">gridCursor</a> and the base list&#39;s <a href="#listselected">listSelected</a>: bright white on blue. It carries its own background (not <code>listSelected</code>&#39;s cyan, which matches a normal row), so a selected row reads clearly even against zebra striping. Painted for every row whose key is in the selection set; the focused-cell cursor and the pending-commit marker win over it.</p><hr><h3 id="historybuttonarrow" tabindex="-1">historyButtonArrow <a class="header-anchor" href="#historybuttonarrow" aria-label="Permalink to &quot;historyButtonArrow&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>historyButtonArrow</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L137" target="_blank" rel="noreferrer">color/theme.ts:137</a></p><p>The history dropdown button&#39;s <code>↓</code> arrow: black on green.</p><hr><h3 id="historybuttonsides" tabindex="-1">historyButtonSides <a class="header-anchor" href="#historybuttonsides" aria-label="Permalink to &quot;historyButtonSides&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>historyButtonSides</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L135" target="_blank" rel="noreferrer">color/theme.ts:135</a></p><p>The history dropdown button&#39;s <code>▐</code>/<code>▌</code> half-block sides: green on lightGray.</p><hr><h3 id="historyviewer" tabindex="-1">historyViewer <a class="header-anchor" href="#historyviewer" aria-label="Permalink to &quot;historyViewer&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>historyViewer</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L145" target="_blank" rel="noreferrer">color/theme.ts:145</a></p><p>A history list&#39;s normal (unfocused) row: white on blue.</p><hr><h3 id="historyviewerfocused" tabindex="-1">historyViewerFocused <a class="header-anchor" href="#historyviewerfocused" aria-label="Permalink to &quot;historyViewerFocused&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>historyViewerFocused</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L147" target="_blank" rel="noreferrer">color/theme.ts:147</a></p><p>A history list&#39;s focused row: white on green.</p><hr><h3 id="historywindow" tabindex="-1">historyWindow <a class="header-anchor" href="#historywindow" aria-label="Permalink to &quot;historyWindow&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>historyWindow</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a> &amp; <code>object</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L143" target="_blank" rel="noreferrer">color/theme.ts:143</a></p><p>The history popup window — the same shape as <a href="#window">window</a> (interior fg/bg + <code>border</code> + <code>icon</code>). It renders as a <strong>blue</strong> window (white-on-blue border, brightGreen icon accent) even when opened from a gray dialog.</p><h4 id="type-declaration-2" tabindex="-1">Type Declaration <a class="header-anchor" href="#type-declaration-2" aria-label="Permalink to &quot;Type Declaration&quot;">​</a></h4><h5 id="border-1" tabindex="-1">border <a class="header-anchor" href="#border-1" aria-label="Permalink to &quot;border&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>border</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><h5 id="icon-1" tabindex="-1">icon <a class="header-anchor" href="#icon-1" aria-label="Permalink to &quot;icon&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>icon</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><hr><h3 id="indicatordragging" tabindex="-1">indicatorDragging <a class="header-anchor" href="#indicatordragging" aria-label="Permalink to &quot;indicatorDragging&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>indicatorDragging</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L268" target="_blank" rel="noreferrer">color/theme.ts:268</a></p><p>The <code>line:col</code> indicator while its window is being dragged: brightGreen on blue, drawn over a <code>─</code> fill.</p><hr><h3 id="indicatornormal" tabindex="-1">indicatorNormal <a class="header-anchor" href="#indicatornormal" aria-label="Permalink to &quot;indicatorNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>indicatorNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L263" target="_blank" rel="noreferrer">color/theme.ts:263</a></p><p>The <code>line:col</code> indicator in an editor window&#39;s bottom border, at rest: white on blue, drawn over a <code>═</code> fill while the window is not being dragged.</p><hr><h3 id="inputarrows" tabindex="-1">inputArrows <a class="header-anchor" href="#inputarrows" aria-label="Permalink to &quot;inputArrows&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>inputArrows</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L104" target="_blank" rel="noreferrer">color/theme.ts:104</a></p><p>The input-line <code>◄</code>/<code>►</code> scroll arrows shown when text overflows: brightGreen on blue.</p><hr><h3 id="inputnormal" tabindex="-1">inputNormal <a class="header-anchor" href="#inputnormal" aria-label="Permalink to &quot;inputNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>inputNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L95" target="_blank" rel="noreferrer">color/theme.ts:95</a></p><p>An input-line field, unfocused: white on blue. A focused field uses the same color (<a href="#inputselected">inputSelected</a>) — focus is signalled by the blinking caret, not by a color change. The reverse-video highlight over a text selection is a separate role, <a href="#inputselection">inputSelection</a>.</p><hr><h3 id="inputplaceholder" tabindex="-1">inputPlaceholder <a class="header-anchor" href="#inputplaceholder" aria-label="Permalink to &quot;inputPlaceholder&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>inputPlaceholder</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L109" target="_blank" rel="noreferrer">color/theme.ts:109</a></p><p>The muted hint text shown in an empty input line (its placeholder): a dimmed, secondary foreground on the input field&#39;s own background — visible but clearly not the typed value.</p><hr><h3 id="inputselected" tabindex="-1">inputSelected <a class="header-anchor" href="#inputselected" aria-label="Permalink to &quot;inputSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>inputSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L97" target="_blank" rel="noreferrer">color/theme.ts:97</a></p><p>An input-line field, focused: white on blue — the same as <a href="#inputnormal">inputNormal</a>.</p><hr><h3 id="inputselection" tabindex="-1">inputSelection <a class="header-anchor" href="#inputselection" aria-label="Permalink to &quot;inputSelection&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>inputSelection</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L102" target="_blank" rel="noreferrer">color/theme.ts:102</a></p><p>The highlight band over selected text inside an input line: white on green. Distinct from the focused <strong>field</strong> color (<a href="#inputselected">inputSelected</a>).</p><hr><h3 id="label" tabindex="-1">label <a class="header-anchor" href="#label" aria-label="Permalink to &quot;label&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>label</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L64" target="_blank" rel="noreferrer">color/theme.ts:64</a></p><p>A control label&#39;s normal text: black on lightGray.</p><hr><h3 id="labelselected" tabindex="-1">labelSelected <a class="header-anchor" href="#labelselected" aria-label="Permalink to &quot;labelSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>labelSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L66" target="_blank" rel="noreferrer">color/theme.ts:66</a></p><p>A label when its linked control is focused: white on lightGray.</p><hr><h3 id="labelshortcut" tabindex="-1">labelShortcut <a class="header-anchor" href="#labelshortcut" aria-label="Permalink to &quot;labelShortcut&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>labelShortcut</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L68" target="_blank" rel="noreferrer">color/theme.ts:68</a></p><p>A label&#39;s <code>~hotkey~</code> accent character: yellow on lightGray.</p><hr><h3 id="listdivider" tabindex="-1">listDivider <a class="header-anchor" href="#listdivider" aria-label="Permalink to &quot;listDivider&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>listDivider</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L126" target="_blank" rel="noreferrer">color/theme.ts:126</a></p><p>A list&#39;s inter-column divider <code>│</code> (unused for a single-column list): blue on cyan.</p><hr><h3 id="listfocused" tabindex="-1">listFocused <a class="header-anchor" href="#listfocused" aria-label="Permalink to &quot;listFocused&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>listFocused</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L122" target="_blank" rel="noreferrer">color/theme.ts:122</a></p><p>A list&#39;s focused row — the primary focus signal in color mode: white on green.</p><hr><h3 id="listnormal" tabindex="-1">listNormal <a class="header-anchor" href="#listnormal" aria-label="Permalink to &quot;listNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>listNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L120" target="_blank" rel="noreferrer">color/theme.ts:120</a></p><p>A list&#39;s normal (unfocused) row: black on cyan.</p><hr><h3 id="listselected" tabindex="-1">listSelected <a class="header-anchor" href="#listselected" aria-label="Permalink to &quot;listSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>listSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L124" target="_blank" rel="noreferrer">color/theme.ts:124</a></p><p>A list&#39;s selected row: yellow on cyan.</p><hr><h3 id="memonormal" tabindex="-1">memoNormal <a class="header-anchor" href="#memonormal" aria-label="Permalink to &quot;memoNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>memoNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L256" target="_blank" rel="noreferrer">color/theme.ts:256</a></p><p>A dialog-embedded memo&#39;s normal cell: black on cyan.</p><hr><h3 id="memoselected" tabindex="-1">memoSelected <a class="header-anchor" href="#memoselected" aria-label="Permalink to &quot;memoSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>memoSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L258" target="_blank" rel="noreferrer">color/theme.ts:258</a></p><p>A memo&#39;s selected text: white on green.</p><hr><h3 id="menubar" tabindex="-1">menuBar <a class="header-anchor" href="#menubar" aria-label="Permalink to &quot;menuBar&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>menuBar</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L34" target="_blank" rel="noreferrer">color/theme.ts:34</a></p><p>The top menu bar.</p><hr><h3 id="menuselected" tabindex="-1">menuSelected <a class="header-anchor" href="#menuselected" aria-label="Permalink to &quot;menuSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>menuSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L36" target="_blank" rel="noreferrer">color/theme.ts:36</a></p><p>The highlighted (hovered/open) menu item.</p><hr><h3 id="outlinefocused" tabindex="-1">outlineFocused <a class="header-anchor" href="#outlinefocused" aria-label="Permalink to &quot;outlineFocused&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>outlineFocused</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L152" target="_blank" rel="noreferrer">color/theme.ts:152</a></p><p>An outline/tree focused row — a distinct inverted bar: blue on lightGray.</p><hr><h3 id="outlinenormal" tabindex="-1">outlineNormal <a class="header-anchor" href="#outlinenormal" aria-label="Permalink to &quot;outlineNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>outlineNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L150" target="_blank" rel="noreferrer">color/theme.ts:150</a></p><p>An outline/tree normal row (an expanded node or a leaf): yellow on blue.</p><hr><h3 id="outlinenotexpanded" tabindex="-1">outlineNotExpanded <a class="header-anchor" href="#outlinenotexpanded" aria-label="Permalink to &quot;outlineNotExpanded&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>outlineNotExpanded</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L156" target="_blank" rel="noreferrer">color/theme.ts:156</a></p><p>An outline/tree collapsed-node&#39;s text: white on blue.</p><hr><h3 id="outlineselected" tabindex="-1">outlineSelected <a class="header-anchor" href="#outlineselected" aria-label="Permalink to &quot;outlineSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>outlineSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L154" target="_blank" rel="noreferrer">color/theme.ts:154</a></p><p>An outline/tree selected row: brightGreen on blue.</p><hr><h3 id="progressfill" tabindex="-1">progressFill <a class="header-anchor" href="#progressfill" aria-label="Permalink to &quot;progressFill&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>progressFill</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L172" target="_blank" rel="noreferrer">color/theme.ts:172</a></p><p>A progress bar&#39;s filled portion: brightCyan on blue — a brighter sibling of <a href="#scrollbarpage">scrollBarPage</a>. Paints the <code>█</code>/eighth-block sub-cell fill (and the whole-cell <code>#</code> fill in ASCII mode).</p><hr><h3 id="progresstrack" tabindex="-1">progressTrack <a class="header-anchor" href="#progresstrack" aria-label="Permalink to &quot;progressTrack&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>progressTrack</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L178" target="_blank" rel="noreferrer">color/theme.ts:178</a></p><p>A progress bar&#39;s unfilled track: cyan on blue (identical to <a href="#scrollbarpage">scrollBarPage</a>), so the fill reads brighter than the track on the shared blue field. Paints the <code>░</code> track (and the whole-cell <code>-</code> track in ASCII mode).</p><hr><h3 id="scrollbarcontrols" tabindex="-1">scrollBarControls <a class="header-anchor" href="#scrollbarcontrols" aria-label="Permalink to &quot;scrollBarControls&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>scrollBarControls</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L118" target="_blank" rel="noreferrer">color/theme.ts:118</a></p><p>A scrollbar&#39;s controls — the <code>▲▼◄►</code> arrows and the <code>■</code> thumb: cyan on blue.</p><hr><h3 id="scrollbarpage" tabindex="-1">scrollBarPage <a class="header-anchor" href="#scrollbarpage" aria-label="Permalink to &quot;scrollBarPage&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>scrollBarPage</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L116" target="_blank" rel="noreferrer">color/theme.ts:116</a></p><p>A scrollbar&#39;s track / page area (the <code>▒</code>/<code>▓</code> fill): cyan on blue. The track and the controls share a color; the glyph (<code>■</code> thumb vs <code>▒</code> track) is the visual distinction.</p><hr><h3 id="shadow" tabindex="-1">shadow <a class="header-anchor" href="#shadow" aria-label="Permalink to &quot;shadow&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>shadow</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L280" target="_blank" rel="noreferrer">color/theme.ts:280</a></p><p>The window drop-shadow: darkGray on black.</p><hr><h3 id="sliderthumb" tabindex="-1">sliderThumb <a class="header-anchor" href="#sliderthumb" aria-label="Permalink to &quot;sliderThumb&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>sliderThumb</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L188" target="_blank" rel="noreferrer">color/theme.ts:188</a></p><p>A slider&#39;s thumb — the <code>█</code> block marking the current value: a solid blue-on-lightGray block, brighter than the <a href="#slidertrack">sliderTrack</a> groove.</p><hr><h3 id="slidertrack" tabindex="-1">sliderTrack <a class="header-anchor" href="#slidertrack" aria-label="Permalink to &quot;sliderTrack&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>sliderTrack</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L183" target="_blank" rel="noreferrer">color/theme.ts:183</a></p><p>A slider&#39;s groove — the <code>─</code>/<code>│</code> rule the thumb travels along: a dim darkGray-on-lightGray line on the gray dialog field where sliders live.</p><hr><h3 id="splitter" tabindex="-1">splitter <a class="header-anchor" href="#splitter" aria-label="Permalink to &quot;splitter&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>splitter</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L286" target="_blank" rel="noreferrer">color/theme.ts:286</a></p><p>A split-pane divider at rest: lightGray on blue, drawn over the divider&#39;s <code>│</code> (row split) or <code>─</code> (col split) fill, with a <code>▓</code> grab mark at its midpoint.</p><hr><h3 id="splitterdragging" tabindex="-1">splitterDragging <a class="header-anchor" href="#splitterdragging" aria-label="Permalink to &quot;splitterDragging&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>splitterDragging</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L292" target="_blank" rel="noreferrer">color/theme.ts:292</a></p><p>A split-pane divider while it is being dragged: brightGreen on blue — the dragging counterpart of <a href="#splitter">splitter</a>, mirroring how <a href="#indicatordragging">indicatorDragging</a> relates to <a href="#indicatornormal">indicatorNormal</a>.</p><hr><h3 id="statictext" tabindex="-1">staticText <a class="header-anchor" href="#statictext" aria-label="Permalink to &quot;staticText&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>staticText</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L62" target="_blank" rel="noreferrer">color/theme.ts:62</a></p><p>Static (non-interactive) text: black on lightGray.</p><hr><h3 id="statusbar" tabindex="-1">statusBar <a class="header-anchor" href="#statusbar" aria-label="Permalink to &quot;statusBar&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>statusBar</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L272" target="_blank" rel="noreferrer">color/theme.ts:272</a></p><p>The status line.</p><hr><h3 id="statusselected" tabindex="-1">statusSelected <a class="header-anchor" href="#statusselected" aria-label="Permalink to &quot;statusSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>statusSelected</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L278" target="_blank" rel="noreferrer">color/theme.ts:278</a></p><p>The status-line <strong>pressed/selected</strong> item (mouse-down feedback): black on green, with a red-on-green hotkey run. The pressed counterpart of <a href="#statusbar">statusBar</a>, mirroring how <a href="#menuselected">menuSelected</a> relates to <a href="#menubar">menuBar</a>.</p><hr><h3 id="tabactive" tabindex="-1">tabActive <a class="header-anchor" href="#tabactive" aria-label="Permalink to &quot;tabActive&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>tabActive</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L162" target="_blank" rel="noreferrer">color/theme.ts:162</a></p><p>The active (selected) tab — the brighter, &quot;raised&quot; button face: white on green, with a yellow accent for the <code>~X~</code> hotkey letter.</p><hr><h3 id="tabdisabled" tabindex="-1">tabDisabled <a class="header-anchor" href="#tabdisabled" aria-label="Permalink to &quot;tabDisabled&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>tabDisabled</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L166" target="_blank" rel="noreferrer">color/theme.ts:166</a></p><p>A disabled tab — dimmed but kept on the green field so it stays part of the strip: darkGray on green.</p><hr><h3 id="tabinactive" tabindex="-1">tabInactive <a class="header-anchor" href="#tabinactive" aria-label="Permalink to &quot;tabInactive&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>tabInactive</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L164" target="_blank" rel="noreferrer">color/theme.ts:164</a></p><p>An inactive tab — the normal button face: black on green, with a yellow <code>~X~</code> hotkey accent.</p><hr><h3 id="tableheader" tabindex="-1">tableHeader <a class="header-anchor" href="#tableheader" aria-label="Permalink to &quot;tableHeader&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>tableHeader</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L132" target="_blank" rel="noreferrer">color/theme.ts:132</a></p><p>A data-grid header row: white on cyan — a bright heading over the same cyan field as the <a href="#listnormal">listNormal</a> rows, distinct from both normal (black-on-cyan) and selected (yellow-on-cyan) rows.</p><hr><h3 id="terminalnormal" tabindex="-1">terminalNormal <a class="header-anchor" href="#terminalnormal" aria-label="Permalink to &quot;terminalNormal&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>terminalNormal</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L270" target="_blank" rel="noreferrer">color/theme.ts:270</a></p><p>Terminal text — a streaming log sink&#39;s normal cell: yellow on blue.</p><hr><h3 id="warningtext" tabindex="-1">warningText <a class="header-anchor" href="#warningtext" aria-label="Permalink to &quot;warningText&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>warningText</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L297" target="_blank" rel="noreferrer">color/theme.ts:297</a></p><p>Advisory/warning body text — a non-blocking caution: amber on the static-text field.</p><hr><h3 id="window" tabindex="-1">window <a class="header-anchor" href="#window" aria-label="Permalink to &quot;window&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>window</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a> &amp; <code>object</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L42" target="_blank" rel="noreferrer">color/theme.ts:42</a></p><p>The active (focused) window chrome. <code>border</code>/<code>title</code> color the frame lines and title text; <code>icon</code> is the brighter accent used for the close/zoom glyphs and the resize grips so they stand out from the frame.</p><h4 id="type-declaration-3" tabindex="-1">Type Declaration <a class="header-anchor" href="#type-declaration-3" aria-label="Permalink to &quot;Type Declaration&quot;">​</a></h4><h5 id="border-2" tabindex="-1">border <a class="header-anchor" href="#border-2" aria-label="Permalink to &quot;border&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>border</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><h5 id="icon-2" tabindex="-1">icon <a class="header-anchor" href="#icon-2" aria-label="Permalink to &quot;icon&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>icon</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><h5 id="title-1" tabindex="-1">title <a class="header-anchor" href="#title-1" aria-label="Permalink to &quot;title&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>title</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><hr><h3 id="windowinactive" tabindex="-1">windowInactive <a class="header-anchor" href="#windowinactive" aria-label="Permalink to &quot;windowInactive&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>windowInactive</strong>: <a href="./ThemeRole.html"><code>ThemeRole</code></a> &amp; <code>object</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/529b195f33af3cc1b43d9b629bd8399fec2d0774/packages/core/src/engine/color/theme.ts#L49" target="_blank" rel="noreferrer">color/theme.ts:49</a></p><p>The <strong>inactive</strong> (background) window chrome — the same shape as <a href="#window">window</a> (fg/bg + border/title + icon) but dimmed, so a background window reads as distinct from the focused one. <code>icon</code> is present for shape symmetry but an inactive window draws no title-bar icons.</p><h4 id="type-declaration-4" tabindex="-1">Type Declaration <a class="header-anchor" href="#type-declaration-4" aria-label="Permalink to &quot;Type Declaration&quot;">​</a></h4><h5 id="border-3" tabindex="-1">border <a class="header-anchor" href="#border-3" aria-label="Permalink to &quot;border&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>border</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><h5 id="icon-3" tabindex="-1">icon <a class="header-anchor" href="#icon-3" aria-label="Permalink to &quot;icon&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>icon</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><h5 id="title-2" tabindex="-1">title <a class="header-anchor" href="#title-2" aria-label="Permalink to &quot;title&quot;">​</a></h5><blockquote><p><code>readonly</code> <strong>title</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote>',403)])])}const m=o(l,[["render",c]]);export{p as __pageData,m as default};
